class HubInfo {
  final String id;
  String name;
  String ip;
  final String room;
  bool paired;
  bool online; // Is the hub currently reachable or not
  Map<String, dynamic> status; // Holds Base/Node status info

  HubInfo({
    required this.id,
    required this.name,
    required this.ip,
    this.paired = false,
    this.online = false,
    this.room = "Unknown",
    Map<String, dynamic>? status,
  }) : status = status ?? {};

  factory HubInfo.fromJson(Map<String, dynamic> j) => HubInfo(
        id: j['id'],
        name: j['name'],
        ip: j['ip'],
        room: j['room'] ?? "Unknown",
        paired: j['paired'] == true,
        online: j['online'] == true,
        status: j['status'] ?? {},
      );

  Map<String, dynamic> toJson() => {
        'id': id,
        'name': name,
        'ip': ip,
        'room': room,
        'paired': paired,
        'online': online,
        'status': status,
      };
}

class DatabaseService {
  final DatabaseReference _db = FirebaseDatabase.instanceFor(
    app: Firebase.app(),
    databaseURL: firebaseURL,
  ).ref();

  Future<List<String>> fetchBases(String hubId) async {
    final snapshot = await _db
        .child('device_list')
        .child('user')
        .child(hubId)
        .get();

    if (!snapshot.exists || snapshot.value == null) return [];

    final raw = snapshot.value;

    if (raw is! Map) return [];

    final hubMap = Map<String, dynamic>.from(
      raw.map((key, value) => MapEntry(key.toString(), value)),
    );

    final bases = hubMap.keys
        .map((key) => key.toString())
        .where((key) => key != "_hub_info")
        .toList();

    bases.sort(naturalCompare);

    return bases;
  }

  Future<void> sendCommand({
    required String hubId,
    required String baseId,
    required String nodeId,
    required String action,
    String value = '',
    String status = 'pending',
  }) async {
    if (hubId.isEmpty || baseId.isEmpty || nodeId.isEmpty || action.isEmpty) {
      throw Exception("Missing command field");
    }

    debugPrint(
      "SENDING COMMAND -> hub=$hubId base=$baseId node=$nodeId action=$action value=$value",
    );

    final commandRef = _db
        .child('command_list')
        .child('commands')
        .push();

    final data = {
      'action': action,
      'base': baseId,
      'hub': hubId,
      'node': nodeId,
      'status': status,
      'time': ServerValue.timestamp,
      'value': value,
    };

    await commandRef.set(data);

    debugPrint('Command sent: ${commandRef.key}');
  }
}

class SendCommandButton extends StatelessWidget {
  final String hubId;
  final String baseId;
  final String nodeId;
  final String action;
  final String buttonText;

  const SendCommandButton({
    super.key,
    required this.hubId,
    required this.baseId,
    required this.nodeId,
    required this.action,
    this.buttonText = 'Send Command',
  });

  @override
  Widget build(BuildContext context) {
    final dbService = DatabaseService();
    return ElevatedButton(
      onPressed: () async {
        try {
          await dbService.sendCommand(
            hubId: hubId,
            baseId: baseId,
            nodeId: nodeId,
            action: action,
          );
          if (context.mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text('Command sent successfully')),
            );
          }
        } catch (e, stack) {
          debugPrint('ERROR: $e');
          debugPrintStack(stackTrace: stack);
          if (context.mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(content: Text('Error: $e')),
            );
          }
        }
      },
      child: Text(buttonText),
    );
  }
}

class CommandDialog extends StatefulWidget {
  final String? initialHubId;

  const CommandDialog({super.key, this.initialHubId});

  @override
  State<CommandDialog> createState() => _CommandDialogState();
}

class _CommandDialogState extends State<CommandDialog> {
  final DatabaseService dbService = DatabaseService();
  final Map<String, List<String>> _basesCache = {};
  Map<String, List<String>> hubBases = {};
  Map<String, List<Map<String, String>>> baseNodes = {};
  bool _loadingBases = false;
  String? selectedHub;
  String? selectedBase;
  String? selectedNode;
  String? selectedAction;

  final List<Map<String, String>> nodes = [
    {'label': 'All Nodes',     'node': 'base'},
    {'label': 'Center Outlet', 'node': 'node_c'},
    {'label': 'Left Node',     'node': 'node_l'},
    {'label': 'Right Node',    'node': 'node_r'},
  ];

  final List<Map<String, String>> actions = [
    {'label': 'Turn ON',  'action': 'power', 'value': 'high'},
    {'label': 'Turn OFF', 'action': 'power', 'value': 'low' },
  ];

  @override
  void initState() {
    super.initState();
    selectedHub = widget.initialHubId;
    if (selectedHub != null) {
      _loadBases(selectedHub!);
    }
  }

  Future<void> _loadBases(String hubId) async {
    setState(() => _loadingBases = true);
    final bases = await dbService.fetchBases(hubId);
    bases.sort(naturalCompare);
    setState(() {
      _basesCache[hubId] = bases;
      _loadingBases = false;
    });
  }

  bool get _canSend {
    return selectedHub != null && selectedBase != null && selectedNode != null && selectedAction != null;
  }

  @override
  Widget build(BuildContext context) {
    final app = context.read<AppState>();
    final hubs = app.discovered.where((h) => h.paired).toList()..sort((a, b) => naturalCompare(a.name, b.name));
    final bases = _basesCache[selectedHub] ?? [];
    return AlertDialog(
      title: const Text('Send Command'),
      content: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // Hub Filter
          DropdownButton<String>(
            value: selectedHub,
            hint: const Text("Select Hub"),
            isExpanded: true,
            items: hubs
              .map((h) => DropdownMenuItem(
                value: h.id, 
                child: Text(h.name)
                ))
              .toList(),
            onChanged: (value) {
              setState(() {
                selectedHub = value;
                selectedBase = null;
                selectedNode = null;
              });
              if (value != null) {
                _loadBases(value);
              }
            },
          ),
          const SizedBox(height: 10),

          // Base Filter
          DropdownButton<String>(
            value: selectedBase,
            hint: const Text("Select Base"),
            isExpanded: true,
            items: bases
              .map((b) => DropdownMenuItem(
                  value: b,
                  child: Text(b),
                ))
              .toList(), 
            onChanged: (selectedHub == null || _loadingBases) ? null : (value) {
              setState(() {
                selectedBase = value;
                selectedNode = null;
              });
            },
          ),
          const SizedBox(height: 10),

          // Node Filter
          DropdownButton<String>(
            value: nodes.any((n) => n['node'] == selectedNode) ? selectedNode : null,
            hint: const Text("Select Node"),
            isExpanded: true,
            items: nodes
              .map((n) => DropdownMenuItem<String>(
                  value: n['node']!,
                  child: Text(n['label']!),
                ))
              .toList(), 
            onChanged: selectedBase == null ? null : (value) {
              setState(() {
                selectedNode = value;
                selectedAction = null;
              });
            },
          ),
          const SizedBox(height: 10),

          // Action Filter
          DropdownButton<String>(
            value: actions.any((a) => a['label'] == selectedAction) ? selectedAction : null,
            hint: const Text("Select Action"),
            isExpanded: true,
            items: actions
              .map((a) => DropdownMenuItem<String>(
                  value: a['label']!,
                  child: Text(a['label']!),
                ))
              .toList(),
            onChanged: selectedNode == null ? null : (value) {
              setState(() => selectedAction = value);
            },
          ),
        ],
      ),
      actions: [
        TextButton(
          onPressed: () => Navigator.pop(context),
          child: const Text('Cancel'),
        ),
        ElevatedButton.icon(
          icon: const Icon(Icons.send),
          label: const Text('Send'),
          onPressed: _canSend ? () async {
            try {
              final selectedActionMap = actions.firstWhere((a) => a['label'] == selectedAction);
              await dbService.sendCommand(
                hubId: selectedHub!,
                baseId: selectedBase!,
                nodeId: selectedNode!,
                action: selectedActionMap['action']!,
                value: selectedActionMap['value'] ?? '',
              );

              if (context.mounted) {
                Navigator.pop(context);
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text('Sent: $selectedAction to $selectedHub/$selectedBase/$selectedNode')),
                );
              }
            } catch (e) {
              if (context.mounted) {
                ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text('Error: $e')),
                );
              }
            }
          }
        : null, // Button disabled if invalid
        ),
      ],
    );
  }
}

