// AppState (handles login, storage, discovery)
class AppState extends ChangeNotifier {
  final FlutterSecureStorage storage;
  static const _kLastUser = 'smartplug_last_user';
  final FirebaseAuth _auth = FirebaseAuth.instance;
  String? get uid => _auth.currentUser?.uid;
  String _pairedHubsKey() {
    final uid = _auth.currentUser?.uid;
    if (uid == null) {
      throw Exception("User not authenticated");
    }
    return 'smartplug_paired_hubs_$uid';
  }
  bool loaded = false;
  bool loggedIn = false;
  bool isFirstLaunch = true;
  String? username;
  String? activeHubId;
  List<HubInfo> discovered = [];
  StreamSubscription? _hubSubscription;
  int _hubCounter = 0;

  AppState({required this.storage}) {
    _init();
  }

  Future<void> _init() async {
    final prefs = await SharedPreferences.getInstance();

    // Detect fresh install
    final hasRunBefore = prefs.getBool('has_run_before') ?? false;
    if (!hasRunBefore) {
      // If fresh install then wipe secure storage
      await storage.deleteAll();
      await prefs.setBool('has_run_before', true);
      isFirstLaunch = true;
    } else {
      isFirstLaunch = false;
    }

    final user = _auth.currentUser;
    if (user != null) {
      username = user.email?.split('@').first;
      loggedIn = true;
      startRealtimeHubListener();
      await loadPairedHubs();
    }

    // Load paired hubs
    if (_auth.currentUser != null) {
      final pairedJson = await storage.read(key: _pairedHubsKey());
      if (pairedJson != null) {
        try {
          final parsed = jsonDecode(pairedJson) as List<dynamic>;
          for (var e in parsed) {
            if (e is Map && e['id'] != null && e['id'].toString().startsWith("hub-")) {
              final numPart = int.tryParse(e['id'].toString().substring(4));
              if (numPart != null && numPart > _hubCounter) {
                _hubCounter = numPart;
              }
            }
          }
        } catch (e) {
          debugPrint('Error: $e');
        }
      }
    }
    loaded = true;
    notifyListeners();
  }

  Future<void> createAccount(String username, String password) async {
    discovered = [];
    activeHubId = null;
    _hubSubscription?.cancel();
    final fakeEmail = '$username@app.local';
    final cred = await _auth.createUserWithEmailAndPassword(
      email: fakeEmail,
      password: password,
    );
    final uid = cred.user!.uid;
    await storage.write(key: 'last_uid', value: uid);
    this.username = username;
    loggedIn = true;
    isFirstLaunch = false;
    await loadPairedHubs();
    startRealtimeHubListener();
    debugPrint("ACCOUNT CREATED:");
    debugPrint("UID: ${cred.user?.uid}");
    debugPrint("EMAIL: ${cred.user?.email}");
    testFirebaseRoot(); // DEBUG
    notifyListeners();
  }

  Future<void> login(String username, String password) async {
    discovered = [];
    activeHubId = null;
    _hubSubscription?.cancel();
    final fakeEmail = '$username@app.local';
    final cred = await _auth.signInWithEmailAndPassword(
      email: fakeEmail,
      password: password,
    );
    final uid = cred.user!.uid;
    await storage.write(key: 'last_uid', value: uid);
    this.username = username;
    loggedIn = true;
    isFirstLaunch = false;
    await loadPairedHubs();
    startRealtimeHubListener();
    debugPrint("LOGIN SUCCESS:");
    debugPrint("UID: ${cred.user?.uid}");
    debugPrint("EMAIL: ${cred.user?.email}");
    testFirebaseRoot(); // DEBUG
    notifyListeners();
  }

  // Log out current user
  Future<void> logout() async {
    _hubSubscription?.cancel();
    await _auth.signOut();
    loggedIn = false;
    username = null;
    discovered = [];
    activeHubId = null;
    notifyListeners();
  }

  // Delete the current user's account
  Future<void> deleteAccount(String password) async {
    final user = _auth.currentUser;
    if (user == null || username == null) return;
    final fakeEmail = '$username@app.local';
    try {
      // Re-authenticate
      final credential = EmailAuthProvider.credential(
        email: fakeEmail,
        password: password,
      );
      await user.reauthenticateWithCredential(credential);
      // Delete account
      await user.delete();
      // Cleanup
      _hubSubscription?.cancel();
      await storage.delete(key: _pairedHubsKey());
      await storage.delete(key: _kLastUser);
      loggedIn = false;
      username = null;
      discovered = [];
      activeHubId = null;
      notifyListeners();
    } on FirebaseAuthException catch (e) {
      throw Exception(_mapDeleteError(e));
    }
  }

  String _mapDeleteError(FirebaseAuthException e) {
    switch (e.code) {
      case 'wrong-password':
        return 'Incorrect password.';
      case 'requires-recent-login':
        return 'Please log in again before deleting your account.';
      default:
        return e.message ?? 'Failed to delete account.';
    }
  }

  // DEBUG: Print all secure storage values - Start
  Future<void> debugPrintSecureStorage() async {
    try {
      final all = await storage.readAll();
      debugPrint("SECURE STORAGE DUMP BEGIN");
      if (all.isEmpty) {
        debugPrint("  (storage is empty)");
      } else {
        for (final key in all.keys) {
          debugPrint("  $key = ${all[key]}");
        }
      }
      debugPrint("SECURE STORAGE DUMP END");
    } catch (e) {
      debugPrint("ERROR READING SECURE STORAGE: $e");
    }
  }
  // DEBUG: Print all secure storage values - End

  Map<String, dynamic> cleanFirebaseMap(Map input) {
    return input.map((key, value) {
      if (value is Map) {
        return MapEntry(key.toString(), cleanFirebaseMap(value));
      }
      return MapEntry(key.toString(), value);
    });
  }

  // Discover Hubs
  Future<void> loadHubsFromFirebase() async {
    final ref = FirebaseDatabase.instanceFor(
      app: Firebase.app(),
      databaseURL: firebaseURL,
    ).ref();
    final snapshot = await ref.child('device_list').child('user').get();
    debugPrint("=== loadHubsFromFirebase SNAPSHOT EXISTS: ${snapshot.exists}");
    debugPrint("=== loadHubsFromFirebase RAW TYPE: ${snapshot.value.runtimeType}");
    debugPrint("=== loadHubsFromFirebase RAW VALUE: ${snapshot.value}");
    if (!snapshot.exists || snapshot.value == null) {
      discovered = [];
      notifyListeners();
      return;
    }
    final raw = snapshot.value;
    final Map<dynamic, dynamic> data = raw is Map ? raw : Map<dynamic, dynamic>.from({});
    final hubsMap = Map<dynamic, dynamic>.from(data);
    List<HubInfo> loadedHubs = [];
    hubsMap.forEach((hubId, hubData) {
      if (hubData is! Map) return;
      final hubMap = Map<String, dynamic>.from(hubData.map((k, v) => MapEntry(k.toString(), v)));
      final infoRaw = hubMap['_hub_info'];
      Map<String, dynamic> info = {};
      if (infoRaw is Map) {
        info = Map<String, dynamic>.from(
          infoRaw.map((k, v) => MapEntry(k.toString(), v)),
        );
      }
      final firstBase = hubMap.values.firstWhere(
        (v) => v is Map,
        orElse: () => {},
      );
      Map<String, dynamic> baseInfo = {};
      if (firstBase is Map) {
        baseInfo = Map<String, dynamic>.from(firstBase.map((k, v) => MapEntry(k.toString(), v)));
      }
      final baseList = hubMap.keys.where((k) => k.toString() != "_hub_info").toList();
      loadedHubs.add(
        HubInfo(
          id: hubId.toString(),
          name: info['name'] ?? hubId.toString(),
          ip: info['ip'] ?? baseInfo['ip'] ?? '',
          room: 'Unknown',
          paired: true,
          online: true,
          status: {
            "bases": baseList,
            "raw": cleanFirebaseMap(hubMap),
          },
        ),
      );
    });
    loadedHubs.sort((a, b) => naturalCompare(a.name, b.name));
    discovered = loadedHubs;
    if (activeHubId == null && discovered.isNotEmpty) {
      activeHubId = discovered.first.id;
    }
    notifyListeners();
    debugPrint("=== HUBS LOADED: ${discovered.length}");
    debugPrint("FINAL HUB LIST:");
    for (final h in discovered) {
      debugPrint("${h.id} | paired=${h.paired} | online=${h.online}");
    }
  }

  void startRealtimeHubListener() {
    final ref = FirebaseDatabase.instanceFor(
      app: Firebase.app(),
      databaseURL: firebaseURL,
    ).ref().child('device_list').child('user');
    _hubSubscription?.cancel();
    _hubSubscription = ref.onValue.listen((event) {
      final raw = event.snapshot.value;
      debugPrint("=== HUB LISTENER SNAPSHOT EXISTS: ${event.snapshot.exists}");
      debugPrint("=== HUB LISTENER RAW TYPE: ${event.snapshot.value.runtimeType}");
      debugPrint("=== HUB LISTENER RAW VALUE: ${event.snapshot.value}");
      if (raw == null || raw is! Map) {
        discovered = [];
        activeHubId = null;
        notifyListeners();
        return;
      }
      final hubSection = Map<dynamic, dynamic>.from(raw);
      final List<HubInfo> updatedHubs = [];
      for (final entry in hubSection.entries) {
        final hubId = entry.key.toString();
        if (hubId == "_hub_info") continue;
        if (entry.value is! Map) continue;
        final hubMap = Map<String, dynamic>.from(entry.value);
        final infoRaw = hubMap['_hub_info'];
        Map<String, dynamic> info = {};
        if (infoRaw is Map) {
          info = Map<String, dynamic>.from(infoRaw);
        }
        final firstBase = hubMap.values.firstWhere(
          (v) => v is Map,
          orElse: () => {},
        );
        Map<String, dynamic> baseInfo = {};
        if (firstBase is Map) {
          baseInfo = Map<String, dynamic>.from(firstBase);
        }
        final existingHub = discovered.where((h) => h.id == hubId).firstOrNull;
        final bases = hubMap.keys.where((k) => k.toString() != "_hub_info").map((k) => k.toString()).toList()..sort(naturalCompare);
        updatedHubs.add(
          HubInfo(
            id: hubId,
            name: info['name'] ?? existingHub?.name ?? hubId,
            ip: info['ip'] ?? baseInfo['ip'] ?? existingHub?.ip ?? '',
            room: existingHub?.room ?? 'Unknown',
            paired: true,
            online: true,
            status: {
              "bases": bases,
              "raw": hubMap,
            },
          ),
        );
      }
      updatedHubs.sort((a, b) => naturalCompare(a.name, b.name));
      discovered = updatedHubs;
      if (activeHubId != null && !discovered.any((h) => h.id == activeHubId)) {
        activeHubId = null;
      }
      debugPrint("=== POLL UPDATE COMPLETE (${discovered.length} hubs)");
      notifyListeners();
    });
  }

  // DEBUG START
  Future<void> testFirebaseRoot() async {
    final ref = FirebaseDatabase.instance.ref();
    final snapshot = await ref.get();
    debugPrint("ROOT EXISTS: ${snapshot.exists}");
    debugPrint("ROOT VALUE: ${snapshot.value}");
  }
  // DEBUG END

  // Pair or unpair a hub
  Future<void> pairHub(String hubId, bool pair) async {
    // Find hub in discovered list
    final idx = discovered.indexWhere((h) => h.id == hubId);
    if (idx == -1) return;
    // Update paired state
    discovered[idx].paired = pair;
    notifyListeners();
    // Save updated paired hubs for this user
    if (_auth.currentUser != null) {
      final paired = discovered.where((h) => h.paired).map((h) => h.toJson()).toList();
      await storage.write(key: _pairedHubsKey(), value: jsonEncode(paired));
    }
  }

  // Set the Active Hub
  void setActiveHub(String? hubId) {
    activeHubId = hubId;
    notifyListeners();
  }

  // Load hubs paired to a user
  Future<void> loadPairedHubs() async {
    if (username == null) return;
    final pairedJson = await storage.read(key: _pairedHubsKey());
    if (pairedJson == null) return;
    try {
      final parsed = jsonDecode(pairedJson) as List<dynamic>;
      discovered = parsed.map((e) => HubInfo.fromJson(Map<String, dynamic>.from(e))).toList();
      // Ensure all are marked paired
      for (var h in discovered) {
        h.paired = true;
      }
    } catch (e) {
      debugPrint('Error loading paired hubs: $e');
    }
    notifyListeners();
  }

  @override
  void dispose() {
    _hubSubscription?.cancel();
    super.dispose();
  }
}

// Gemini Integration
class ParsedCommand {
  final bool valid;
  final String? node;
  final String? action;
  final String? value;
  final String? error;

  ParsedCommand({
    required this.valid,
    this.node,
    this.action,
    this.value,
    this.error,
  });

  factory ParsedCommand.fromJson(Map<String, dynamic> json) {
    return ParsedCommand(
      valid: json['valid'] == true,
      node: json['node']?.toString(),
      action: json['action']?.toString(),
      value: json['value']?.toString() ?? '',
      error: json['error']?.toString(),
    );
  }

  bool get hasRequiredFields {
    return valid &&
        node != null &&
        node!.isNotEmpty &&
        action != null &&
        action!.isNotEmpty;
  }
}

class GeminiVoiceParser {
  final model = FirebaseAI.googleAI().generativeModel(
    model: 'gemini-2.0-flash',
  );

  Future<ParsedCommand> parse(String text) async {
    final prompt = '''
      Convert this voice command into JSON for a smart plug system.

      SYSTEM RULES:
      - Nodes: node_l, node_r, node_c, node_a
      - Actions:
        turn_on
        turn_off
        toggle
        emergency_off
        reset_safe
        power_low
        power_medium
        power_high
        restart

      - Values:
        "high", "medium", "low", or "" empty string

      Return ONLY JSON.

      Command: "$text"

      FORMAT:
      {
        "valid": true,
        "node": "node_l",
        "action": "turn_on",
        "value": "high",
        "error": null
      }
      ''';

    try {
      final response = await model.generateContent([
        Content.text(prompt),
      ]);

      final raw = response.text ?? '{}';

      final start = raw.indexOf('{');
      final end = raw.lastIndexOf('}');

      if (start == -1 || end == -1 || end <= start) {
        return ParsedCommand(
          valid: false,
          error: 'Gemini did not return valid JSON',
        );
      }

      final cleaned = raw.substring(start, end + 1).trim();
      final decoded = jsonDecode(cleaned);

      if (decoded is! Map<String, dynamic>) {
        return ParsedCommand(
          valid: false,
          error: 'Invalid JSON structure',
        );
      }

      return ParsedCommand.fromJson(decoded);
    } catch (e) {
      return ParsedCommand(
        valid: false,
        error: 'Failed to parse command: $e',
      );
    }
  }
}

// User Interface
void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  // Initialize Firebase
  await Firebase.initializeApp(
    options: DefaultFirebaseOptions.currentPlatform,
  );
  final storage = FlutterSecureStorage(
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock,
    ),
  );
  runApp(MultiProvider(
    providers: [ChangeNotifierProvider(create: (_) => AppState(storage: storage))],
    child: const SmartPlugApp(),
  ));
}

class SmartPlugApp extends StatelessWidget {
  const SmartPlugApp({super.key});
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      title: 'SmartPlug',
      theme: ThemeData(useMaterial3: true,colorScheme: ColorScheme.fromSeed(seedColor: Colors.blue),),
      home: const RootRouter(),
    );
  }
}

class RootRouter extends StatelessWidget {
  const RootRouter({super.key});
  @override
  Widget build(BuildContext context) {
    return Consumer<AppState>(
      builder: (context, app, _) {
        debugPrint("ROUTER -> loaded=${app.loaded}, first=${app.isFirstLaunch}, loggedIn=${app.loggedIn}");
        // Display loading indicator
        if (!app.loaded) {
          return const Scaffold(body: Center(child: CircularProgressIndicator()));
        }
        // If first launch, open Setup page
        if (app.isFirstLaunch) {
          return const AuthPage(isSetup: true);
        }
        // If not logged in, open Login page
        if (!app.loggedIn) {
          return const AuthPage(isSetup: false);
        }
        // Otherwise show the "post-login" discover page (simple home)
        return const HomeAfterLogin();
      }
    );
  }
}

// Setup and Login pages
class AuthPage extends StatefulWidget {
  final bool isSetup; // true = setup, false = login
  const AuthPage({super.key, required this.isSetup});
  @override
  State<AuthPage> createState() => _AuthPageState();
}

class _AuthPageState extends State<AuthPage> {
  final _user = TextEditingController();
  final _pw = TextEditingController();
  bool _loading = false;
  String? _message;

  @override
  void dispose() {
    _user.dispose();
    _pw.dispose();
    super.dispose();
  }

  Future<void> _handleSubmit(AppState app) async {
    final u = _user.text.trim();
    final p = _pw.text;
    if (u.isEmpty || p.isEmpty) {
      if (!mounted) return;
      setState(() => _message = 'Enter username and password');
      return;
    }
    if (widget.isSetup && p.length < 8) {
      if (!mounted) return;
      setState(() => _message = 'Password must be at least 8 characters');
      return;
    }
    if (!mounted) return;
    setState(() {
      _loading = true;
      _message = null;
    });
    try {
      if (widget.isSetup) {
        await app.createAccount(u, p);
        await app.loadHubsFromFirebase();
      } else {
        await app.login(u, p);
        await app.loadHubsFromFirebase();
        await app.loadPairedHubs();
      }
      if (!mounted) return;
      Navigator.pushReplacement(
        context,
        MaterialPageRoute(builder: (_) => const HomeAfterLogin()),
      );
    } catch (e) {
      if (!mounted) return;
      String msg = e.toString().replaceFirst('Exception: ', '');
      setState(() => _message = 'Failed: $msg');
    } finally {
      if (mounted) {
        setState(() => _loading = false);
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final app = context.read<AppState>();
    final title = widget.isSetup ? 'Create Account' : 'Login';
    final buttonText = widget.isSetup ? 'Create Account' : 'Login';
    final subtitle = widget.isSetup
        ? 'Create your account to begin setup and discover nearby hubs.'
        : 'Enter your credentials to continue.';
    return Scaffold(
      appBar: AppBar(title: Text(title)),
      body: Stack(
        children: [
          Center(
            child: ConstrainedBox(
              constraints: const BoxConstraints(maxWidth: 400),
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.center,
                  children: [
                    Text(
                      subtitle,
                      textAlign: TextAlign.center,
                      style: const TextStyle(fontSize: 16),
                    ),
                    const SizedBox(height: 20),

                    TextField(
                      controller: _user,
                      decoration: const InputDecoration(labelText: 'Username'),
                    ),
                    const SizedBox(height: 10),

                    TextField(
                      controller: _pw,
                      obscureText: true,
                      decoration: const InputDecoration(labelText: 'Password'),
                    ),
                    const SizedBox(height: 20),

                    ElevatedButton(
                      onPressed: _loading ? null : () => _handleSubmit(app),
                      child: Text(buttonText),
                    ),

                    if (widget.isSetup)
                      TextButton(
                        onPressed: _loading
                            ? null
                            : () {
                                Navigator.pushReplacement(
                                  context,
                                  MaterialPageRoute(
                                    builder: (_) => const AuthPage(isSetup: false),
                                  ),
                                );
                              },
                        child: const Text('I already have an account'),
                      ),

                    if (!widget.isSetup)
                      TextButton(
                        onPressed: _loading
                            ? null
                            : () {
                                Navigator.pushReplacement(
                                  context,
                                  MaterialPageRoute(
                                    builder: (_) => const AuthPage(isSetup: true),
                                  ),
                                );
                              },
                        child: const Text('Create a new account'),
                      ),

                    if (_message != null) ...[
                      const SizedBox(height: 12),
                      Center(
                        child: Text(
                          _message!,
                          textAlign: TextAlign.center,
                          style: const TextStyle(color: Colors.red),
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ),
          ),

          if (_loading)
            Container(
              color: const Color.fromARGB(255, 0, 0, 0).withAlpha((0.3 * 255).round()),
              child: const Center(
                child: CircularProgressIndicator(),
              ),
            ),
        ],
      ),
    );
  }
}

// Home page
class HomeAfterLogin extends StatelessWidget {
  const HomeAfterLogin({super.key});

  Future<void> _handleDelete(BuildContext context) async {
    final app = context.read<AppState>();
    final passwordController = TextEditingController();
    final password = await showDialog<String>(
      context: context,
      builder: (dialogContext) => AlertDialog(
        title: const Text('Confirm Password'),
        content: TextField(
          controller: passwordController,
          obscureText: true,
          decoration: const InputDecoration(labelText: 'Password'),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(dialogContext),
            child: const Text('Cancel'),
          ),
          TextButton(
            onPressed: () => Navigator.pop(dialogContext, passwordController.text),
            child: const Text('Confirm'),
          ),
        ],
      ),
    );
    if (password == null || password.isEmpty) return;
    try {
      await app.deleteAccount(password);
      if (!context.mounted) return;
      Navigator.pushAndRemoveUntil(
        context,
        MaterialPageRoute(builder: (_) => const AuthPage(isSetup: true)),
        (route) => false,
      );
    } catch (e) {
      if (!context.mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text(e.toString())),
      );
    } finally {
      passwordController.dispose();
    }
  }

  @override
  Widget build(BuildContext context) {
    final app = context.watch<AppState>();
    final visibleHubs = app.activeHubId == null ? app.discovered : app.discovered.where((h) => h.id == app.activeHubId).toList()..sort((a, b) => naturalCompare(a.name, b.name));
    final discoveredHubs = app.discovered.where((h) => !h.paired).toList();

    // Combine hubs with headers
    final List<Widget> hubListItems = [];

    if (visibleHubs.isNotEmpty) {
      hubListItems.add(const Text('Connected Hubs', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)));
      hubListItems.add(const SizedBox(height: 8));
      hubListItems.addAll(
        visibleHubs.map(
          (hub) => Card(
            child: Theme(
              data: Theme.of(context).copyWith(
                dividerColor: Colors.transparent,
              ),
              child: ExpansionTile(
                title: Text("Hub: ${hub.name}"),
                subtitle: Text('${hub.online ? "Online" : "Offline"} • IP Address: ${hub.ip}'),
                children: [
                  Builder(
                    builder: (context) {
                      final rawBases = (hub.status["bases"] as List?) ?? [];
                      final bases = rawBases.map((b) => b.toString()).toList()..sort(naturalCompare);
                      if (bases.isEmpty) {
                        return const Padding(
                          padding: EdgeInsets.all(12.0),
                          child: Text("No bases found"),
                        );
                      }
                      return Column(
                        children: bases.map((baseId) {
                          final raw = hub.status["raw"];
                          final baseData = (raw is Map && raw[baseId] is Map) ? Map<String, dynamic>.from(raw[baseId] as Map) : <String, dynamic>{};
                          final basePower = parseBool(baseData["base_power"]);
                          return Padding(
                            padding: const EdgeInsets.only(left: 12.0),
                            child: Theme(
                              data: Theme.of(context).copyWith(
                                dividerColor: Colors.transparent,
                              ),
                              child: ExpansionTile(
                                title: Text("Base: $baseId"),
                                subtitle: Text("Status: ${baseData["status_base"] ?? "unknown"} • Power: ${basePower ? "On" : "Off"}"),
                                children: [
                                  Padding(
                                    padding: const EdgeInsets.only(left: 20.0),
                                    child: Builder(
                                      builder: (context) {
                                        return Column(
                                          children: [
                                            ...kNodes.map((n) {
                                              String subtitleText;
                                              if (n['node'] == 'node_a') {
                                                const nodeKeys = ['node_l', 'node_r', 'node_c'];
                                                int attachedCount = 0;
                                                int powerCount = 0;
                                                int total = nodeKeys.length;
                                                for (final key in nodeKeys) {
                                                  final rawNode = baseData[key];
                                                  final data = (rawNode is Map) ? rawNode : <String, dynamic>{};
                                                  final attached = key == 'node_c' ? true : parseBool(data['attached']);
                                                  final power = key == 'node_c' ? parseBool(baseData['base_power']) : parseBool(data['power']);
                                                  if (attached) attachedCount++;
                                                  if (power) powerCount++;
                                                }
                                                subtitleText = "Attached: $attachedCount/$total • Power: $powerCount/$total";
                                              } else if (n['node'] == 'node_c') {
                                                final basePower = parseBool(baseData["base_power"]);
                                                subtitleText = "Attached: Yes • Power: ${basePower ? "On" : "Off"}";
                                              } else {
                                                final nodeData = (baseData[n['node']] is Map) ? Map<String, dynamic>.from(baseData[n['node']] as Map) : <String, dynamic>{};
                                                subtitleText = "Attached: ${parseBool(nodeData['attached']) ? "Yes" : "No"} • Power: ${parseBool(nodeData['power']) ? "On" : "Off"}";
                                              }
                                              return Padding(
                                                padding: const EdgeInsets.only(left: 20.0),
                                                child: ListTile(
                                                  contentPadding: EdgeInsets.zero,
                                                  title: Text(n['label']!),
                                                  subtitle: Text(subtitleText),
                                                ),
                                              );
                                            }),
                                            if (imageBase64 != '')
                                            Padding(
                                              padding: const EdgeInsets.only(top: 0, right: 32),
                                              child: ClipRRect(
                                                borderRadius: BorderRadius.zero,
                                                child: Image.memory(
                                                  base64Decode(imageBase64),
                                                  height: 280,
                                                  width: double.infinity,
                                                  fit: BoxFit.fitWidth
                                                ),
                                              ),
                                            ),
                                          ]
                                        );
                                      },
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          );
                        }).toList(),
                      );
                    },
                  ),
                ],
              ),
            ),
          ),
        ),
      );
      hubListItems.add(const Divider(height: 24));
    }

    if (discoveredHubs.isNotEmpty) {
      hubListItems.add(const Text('Discovered Hubs', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)));
      hubListItems.add(const SizedBox(height: 8));
      hubListItems.addAll(discoveredHubs.map((h) => Card(
        child: ListTile(
          title: Text(h.name),
          subtitle: Text('${h.ip} • id: ${h.id}'),
          trailing: ElevatedButton(
            onPressed: () async {
              final roomName = await showDialog<String>(
                context: context,
                builder: (context) {
                  final roomController = TextEditingController();
                  return AlertDialog(
                    title: const Text('Enter Room Name'),
                    content: TextField(
                      controller: roomController,
                      decoration: const InputDecoration(hintText: 'Living Room, Office, etc.'),
                    ),
                    actions: [
                      TextButton(
                        onPressed: () => Navigator.pop(context),
                        child: const Text('Cancel'),
                      ),
                      TextButton(
                        onPressed: () => Navigator.pop(context, roomController.text.trim()),
                        child: const Text('Done'),
                      ),
                    ],
                  );
                },
              );
              if (roomName != null && roomName.isNotEmpty) {
                final newHub = HubInfo(
                  id: h.id,
                  name: h.name,
                  ip: h.ip,
                  room: roomName,
                  paired: true,
                  online: h.online,
                  status: h.status,
                );
                final idx = app.discovered.indexWhere((hub) => hub.id == h.id);
                if (idx != -1) {
                  app.discovered[idx] = newHub;
                }
                await app.pairHub(newHub.id, true);
                app.setActiveHub(null);
              }
            },
            child: const Text('Pair'),
          ),
        ),
      )));
    } else if (visibleHubs.isEmpty) {
      hubListItems.add(const Center(child: Text('No hubs discovered.')));
    }

    return Scaffold(
      appBar: AppBar(
        title: Text('Welcome ${app.username ?? ''}'),
        actions: [
          // Send Command button
          IconButton(
            icon: const Icon(Icons.send),
            tooltip: 'Send Command',
            onPressed: () {
              showDialog(
                context: context,
                builder: (context) => CommandDialog(
                  initialHubId: app.activeHubId,
                ),
              );
            },
          ),

          // Refresh button
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: 'Discover Hubs',
            onPressed: () async {
              showDialog(
                context: context,
                barrierDismissible: false,
                builder: (_) => const Center(
                  child: CircularProgressIndicator(),
                ),
              );
              await app.loadHubsFromFirebase();
              if (context.mounted) {
                Navigator.pop(context);
              }
            },
          ),

          // Account menu
          PopupMenuButton<String>(
            tooltip: 'Account Menu',
            icon: const Icon(Icons.account_circle),
            onSelected: (value) async {
              if (value == 'signout') {
                await app.logout();
                if (!context.mounted) return;
                Navigator.pushAndRemoveUntil(
                  context,
                  MaterialPageRoute(builder: (_) => const AuthPage(isSetup: false)),
                  (route) => false,
                );
              } else if (value == 'delete') {
                final confirm = await showDialog<bool>(
                  context: context,
                  builder: (context) => AlertDialog(
                    title: const Text('Delete Account?'),
                    content: const Text('This will remove your account and all paired hubs. Are you sure?'),
                    actions: [
                      TextButton(
                        onPressed: () => Navigator.pop(context, false),
                        child: const Text('Cancel'),
                      ),
                      TextButton(
                        onPressed: () => Navigator.pop(context, true),
                        child: const Text('Delete'),
                      ),
                    ],
                  ),
                );
                if (confirm == true) {
                  if (!context.mounted) return;
                  await _handleDelete(context);
                }
              }
            },
            itemBuilder: (context) => [
              PopupMenuItem(
                enabled: false,
                child: Text(app.username ?? '', style: const TextStyle(fontWeight: FontWeight.bold)),
              ),
              const PopupMenuDivider(),
              const PopupMenuItem(value: 'signout', child: Text('Sign Out')),
              const PopupMenuItem(value: 'delete', child: Text('Delete Account')),
            ],
          ),
        ],
      ),
      body: Padding(
        padding: const EdgeInsets.all(12.0),
        child: ListView(
          children: [
            VoiceCommandButton(
              hubId: app.activeHubId,
            ),
            const SizedBox(height: 12),
            Padding(
              padding: const EdgeInsets.all(12.0),
              child: Row(
                children: [
                  // Hub Filter
                  Expanded(
                    child: Builder(
                      builder: (context) {
                        final pairedHubs = app.discovered.where((h) => h.paired).toList();
                        final dropdownItems = [
                          const DropdownMenuItem<String?>(
                            value: null,
                            child: Text("All Hubs"),
                          ),
                          ...pairedHubs.map((h) => DropdownMenuItem<String?>(value: h.id,child: Text(h.name)),
                          )
                        ];
                        final selectedValue = app.activeHubId;
                        return DropdownButton<String?>(
                          value: selectedValue,
                          hint: const Text("All Hubs"),
                          underline: const SizedBox(),
                          isExpanded: true,
                          items: dropdownItems,
                          onChanged: (id) => app.setActiveHub(id),
                        );
                      },
                    ),
                  ),
                  const SizedBox(width: 12),
                ],
              ),
            ),
            if (app.discovered.isEmpty)
              const Padding(
                padding: EdgeInsets.all(12.0),
                child: Text(
                  'Tap refresh to discover nearby hubs as part of setup.',
                  style: TextStyle(fontSize: 16),
                ),
              ),
            ...hubListItems,
          ],
        ),
      ),
    );
  }
}

class VoiceCommandButton extends StatefulWidget {
  final String? hubId;

  const VoiceCommandButton({
    super.key,
    required this.hubId,
  });

  @override
  State<VoiceCommandButton> createState() => _VoiceCommandButtonState();
}

class _VoiceCommandButtonState extends State<VoiceCommandButton> {
  final stt.SpeechToText speech = stt.SpeechToText();
  final GeminiVoiceParser parser = GeminiVoiceParser();

  bool listening = false;
  bool processing = false;

  Future<void> startListening() async {
    if (widget.hubId == null || widget.hubId!.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Select a hub first")),
      );
      return;
    }

    final available = await speech.initialize();

    if (!available) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Speech recognition not available")),
      );
      return;
    }

    setState(() {
      listening = true;
      processing = false;
    });

    speech.listen(
      onResult: (result) async {
        if (!result.finalResult) return;
        if (processing) return;

        processing = true;

        final text = result.recognizedWords;

        try {
          final cmd = await parser.parse(text);

          if (!cmd.hasRequiredFields) {
            if (!mounted) return;

            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: Text(cmd.error ?? "Invalid command"),
              ),
            );

            setState(() {
              listening = false;
              processing = false;
            });

            return;
          }

          await DatabaseService().sendCommand(
            hubId: widget.hubId!,
            baseId: "base_1",
            nodeId: cmd.node!,
            action: cmd.action!,
            value: cmd.value ?? '',
            status: "pending",
          );

          if (!mounted) return;

          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text("Sent: ${cmd.node} ${cmd.action}"),
            ),
          );
        } catch (e) {
          if (!mounted) return;

          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text("Voice command error: $e")),
          );
        } finally {
          if (mounted) {
            setState(() {
              listening = false;
              processing = false;
            });
          }

          await speech.stop();
        }
      },
    );
  }

  @override
  Widget build(BuildContext context) {
    final disabled = listening || widget.hubId == null || widget.hubId!.isEmpty;

    return ElevatedButton.icon(
      onPressed: disabled ? null : startListening,
      icon: const Icon(Icons.mic),
      label: Text(listening ? "Listening..." : "Voice Command"),
    );
  }
}